"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { getRandomComplete } from "@/lib/learningMessages";
import { playFlip, playCelebrate } from "@/lib/sounds";

// ===== 场景卡片数据 =====
const CARDS = [
  {
    id: "temperature",
    frontIcon: "\ud83c\udf21\ufe0f",
    frontLabel: "体温",
    frontDesc: "量体温时会看到什么？",
    backValue: "36.5\u2103",
    backRead: "\u8bfb\u4f5c\uff1a\u4e09\u5341\u516d\u70b9\u4e94",
    color: "var(--accent)",
  },
  {
    id: "height",
    frontIcon: "\ud83d\udcf0",
    frontLabel: "\u8eab\u9ad8",
    frontDesc: "\u4f53\u68c0\u8868\u4e0a\u7684\u6570\u5b57\u957f\u8fd9\u6837",
    backValue: "1.35\u7c73",
    backRead: "\u8bfb\u4f5c\uff1a\u4e00\u70b9\u4e09\u4e94",
    color: "var(--primary)",
  },
  {
    id: "price",
    frontIcon: "\ud83d\uded2",
    frontLabel: "\u4ef7\u683c",
    frontDesc: "\u8d85\u5e02\u6807\u7b7e\u4e0a\u7684\u6570\u5b57",
    backValue: "9.9\u5143",
    backRead: "\u8bfb\u4f5c\uff1a\u4e5d\u70b9\u4e5d",
    color: "var(--accent2)",
  },
] as const;

export default function TouchPage() {
  const [flipped, setFlipped] = useState<Record<string, boolean>>({
    temperature: false,
    height: false,
    price: false,
  });
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const allFlipped = Object.values(flipped).every(Boolean);

  const handleFlip = (id: string) => {
    setFlipped((prev) => ({ ...prev, [id]: !prev[id] }));
    playFlip();
    const willAllFlipped = Object.values({ ...flipped, [id]: !flipped[id] }).every(Boolean);
    if (willAllFlipped) setTimeout(() => playCelebrate(), 300);
  };

  const nextStep = getNextStep("decimal", "touch");

  return (
    <StepShell topicId="decimal" stepId="touch">
      {/* 翻转卡片容器 */}
      <div className="grid grid-cols-1 gap-6 sm:grid-cols-3">
        {CARDS.map((card) => (
          <div
            key={card.id}
            className="cursor-pointer"
            style={{ perspective: "800px" }}
            onClick={() => handleFlip(card.id)}
          >
            <div
              className="relative w-full transition-transform duration-500"
              style={{
                transformStyle: "preserve-3d",
                transform: flipped[card.id] ? "rotateY(180deg)" : "rotateY(0deg)",
              }}
            >
              {/* 正面 */}
              <div
                className="flex flex-col items-center justify-center rounded-[var(--radius)] border-2 border-[var(--border)] bg-[var(--bg-card)] p-8 shadow-[var(--shadow-sm)]"
                style={{
                  backfaceVisibility: "hidden",
                  minHeight: "200px",
                }}
              >
                <div
                  className="mb-3 flex h-16 w-16 items-center justify-center rounded-2xl text-3xl shadow-[var(--shadow-sm)]"
                  style={{ backgroundColor: card.color, color: "white" }}
                >
                  {card.frontIcon}
                </div>
                <h3
                  className="text-lg font-bold"
                  style={{ color: "var(--text)" }}
                >
                  {card.frontLabel}
                </h3>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  {card.frontDesc}
                </p>
                <p className="mt-4 text-xs text-[var(--text-muted)]">
                  {flipped[card.id] ? "\u518d\u70b9\u7ffb\u56de\u6765" : "\u70b9\u51fb\u7ffb\u8f6c\u2192"}
                </p>
              </div>

              {/* 背面 */}
              <div
                className="absolute inset-0 flex flex-col items-center justify-center rounded-[var(--radius)] border-2 bg-[var(--bg-card)] p-8 shadow-[var(--shadow-md)]"
                style={{
                  backfaceVisibility: "hidden",
                  transform: "rotateY(180deg)",
                  minHeight: "200px",
                  borderColor: card.color,
                }}
              >
                <div
                  className="mb-3 rounded-full px-4 py-1.5 text-2xl font-extrabold"
                  style={{ backgroundColor: card.color, color: "white" }}
                >
                  {card.backValue}
                </div>
                <p className="text-sm font-medium text-[var(--text-secondary)]">
                  {card.backRead}
                </p>
                <p className="mt-4 text-xs text-[var(--text-muted)]">
                  \u70b9\u51fb\u7ffb\u56de\u2190
                </p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* 完成卡片 */}
      {allFlipped && (
        <div className="mt-8 animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
          <div className="text-4xl mb-2">\ud83c\udf1f</div>
          <p className="text-lg font-semibold text-[var(--text)]">
            {completeMsg}
          </p>
          <p className="mt-2 text-sm text-[var(--text-secondary)]">
            \u751f\u6d3b\u4e2d\u5230\u5904\u90fd\u6709\u5c0f\u6570\uff0c\u4f53\u6e29\u3001\u8eab\u9ad8\u3001\u4ef7\u683c\u2026\u2026\u90fd\u662f\u5c0f\u6570\uff01
          </p>
          <div className="mt-6 flex justify-center gap-4">
            <button
              onClick={() =>
                setFlipped({ temperature: false, height: false, price: false })
              }
              className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
            >
              \u518d\u770b\u4e00\u904d
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                \u4e0b\u4e00\u6b65\uff1a{nextStep.label} \u2192
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
